import Home from '../Pages/Home';
import Contact from "../Pages/Contact";
import Gallery from "../Pages/Gallery";
import Portfolio from "../Pages/Portfolio";
import Error from "../Pages/Error";

export const routes = [
    {
        path: 'Contact',
        element: <Contact/>
    },
    {
        path: 'Gallery',
        element: <Gallery/>
    },
    {
        path: 'Portfolio',
        element: <Portfolio/>
    },
    {
        path: '/',
        element: <Home/>
    },
    {
        path: '*',
        element: <Error/>
    },
]
